   166→	private transformOrderDataToAnnualSales(
   167→		orderData: TrendingItemOrderDataDto[],
   168→		year: number,
   169→	): IProductAnnualSalesBase[] {
   170→		const dailyOrdersAccumulator: DailyOrdersAccumulator = {};
   171→
   172→		orderData.forEach((order) => {
   173→			if (!order.date_placed || !order.style_id || order.total_orders === undefined) {
   174→				return;
   175→			}
   176→
   177→			const orderDate = new Date(order.date_placed);
   178→			const orderYear = orderDate.getFullYear();
   179→
   180→			if (orderYear !== year || isNaN(orderYear)) {
   181→				return;
   182→			}
   183→
   184→			const styleId = Number(order.style_id);
   185→
   186→			if (this.isLeapDay(orderDate)) {
   187→				return;
   188→			}
   189→
   190→			const adjustedDayIndex = this.getAdjustedDayIndex(orderDate);
   191→
   192→			dailyOrdersAccumulator[styleId] ??= {};
   193→
   194→			const styleAccumulator = dailyOrdersAccumulator[styleId];
   195→			styleAccumulator[year] ??= new Array<number>(365).fill(0);
   196→
   197→			if (adjustedDayIndex >= 0 && adjustedDayIndex < 365) {
   198→				const yearArray = styleAccumulator[year];
   199→				yearArray[adjustedDayIndex] = order.total_orders;
   200→			}
   201→		});
   202→
   203→		const { holidayArray, holidayNames, holidayMultipliers } =
   204→			this.generateHolidayArrays(year);
   205→
   206→		const results: IProductAnnualSalesBase[] = [];
   207→
   208→		for (const styleId in dailyOrdersAccumulator) {
   209→			if (dailyOrdersAccumulator[styleId]?.[year]) {
   210→				const category = this.extractCategoryFromOrders(orderData, Number(styleId));
   211→
   212→				results.push({
   213→					_id: randomUUID(),
   214→					style_id: Number(styleId),
   215→					year: year,
   216→					daily_orders: dailyOrdersAccumulator[styleId][year],
   217→					is_holiday: holidayArray,
   218→					holiday_names: holidayNames,
   219→					holiday_multipliers: holidayMultipliers,
   220→					category: category,
   221→					created_at: new Date(),
   222→					updated_at: new Date(),
   223→				});
   224→			}
   225→		}
   226→
   227→		return results;
   228→	}
