   230→	private generateHolidayArrays(year: number): {
   231→		holidayArray: number[];
   232→		holidayNames: (string | null)[];
   233→		holidayMultipliers: number[];
   234→	} {
   235→		const holidayArray = new Array<number>(365).fill(0);
   236→		const holidayNames: (string | null)[] = new Array<string | null>(365).fill(null);
   237→		const holidayMultipliers = new Array<number>(365).fill(1.0);
   238→
   239→		const startDate = new Date(year, 0, 1);
   240→
   241→		for (let dayIndex = 0; dayIndex < 365; dayIndex++) {
   242→			const currentDate = new Date(startDate);
   243→			currentDate.setDate(currentDate.getDate() + dayIndex);
   244→
   245→			if (currentDate.getFullYear() !== year) {
   246→				break;
   247→			}
   248→
   249→			if (this.isLeapDay(currentDate)) {
   250→				continue;
   251→			}
   252→
   253→			const holidayInfo = HolidayHelpers.getHolidayInfo({ date: currentDate });
   254→			const multiplier = HolidayHelpers.getHolidayEffectMultiplier({ date: currentDate });
   255→
   256→			if (holidayInfo) {
   257→				holidayArray[dayIndex] = 1;
   258→				holidayNames[dayIndex] = holidayInfo.name;
   259→				holidayMultipliers[dayIndex] = multiplier;
   260→			}
   261→		}
   262→
   263→		return { holidayArray, holidayNames, holidayMultipliers };
   264→	}
